public static <T extends Comparable<T>> T max(Collection<T> coll, Comparator<? super T> comp) {
    Iterator<? extends T> i = coll.iterator();
    T candidate = i.next();
    while (i.hasNext()) {
        T next = i.next();
        if (compcompare(next, candidate) > 0)
            candidate = next;
    }
    return candidate;
}

